from CocoTBFramework.components.apb.apb_components import APBMaster, APBSlave

# Memory model — shared across all protocol slave BFMs (every slave gets
# its own instance, pre-seeded with a distinct pattern).
from CocoTBFramework.components.shared.memory_model import MemoryModel


class Bridge4x4RwTB(TBBase):
    """
    Testbench for bridge_4x4_rw bridge.

    Configuration:
        Masters: 4 (cpu_master, dma0_master, dma1_master, gpu_master)
        Slaves:  4 (periph_slave, ddr0_slave, sram_slave, gpu_mem_slave)
        Channels: RW
        Data Width: 256
        Addr Width: 64
        ID Width: 8
    """

    # ----------------------------------------------------------------------
    # Construction
    # ----------------------------------------------------------------------

    def __init__(self, dut):
        super().__init__(dut)
        self.dut = dut
        self.clock = dut.aclk
        self.clock_name = 'aclk'
        self.reset_n = dut.aresetn

        # Bridge configuration
        self.num_masters = 4
        self.num_slaves = 4
        self.data_width = 256
        self.addr_width = 64
        self.id_width = 8

        # Per-slave metadata used by misroute checks and pattern computation.
        # slave_info[i] = (protocol, base_addr, addr_range, data_width)
        self.slave_info = {
            0: ('axi4', 0x00000000, 0x40000000, 32),  # periph_slave
            1: ('axi4', 0x40000000, 0x40000000, 64),  # ddr0_slave
            2: ('axi4', 0x80000000, 0x40000000, 128),  # sram_slave
            3: ('axi4', 0xc0000000, 0x40000000, 256),  # gpu_mem_slave
        }

        # Per-master data width (in bits). Used by master_read/write helpers
        # and by slave_mem_read so verification reads back master-width
        # bytes regardless of the slave's native width.
        self.master_data_width = {
            0: 64,  # cpu_master
            1: 32,  # dma0_master
            2: 128,  # dma1_master
            3: 256,  # gpu_master
        }

        # Slave memory models — one per slave, pre-seeded.
        self.slave_memory = {}
        # Slave BFMs (auto-responds from memory_model).
        # For rw slaves we keep both read+write handles.
        self.slave_rd = {}
        self.slave_wr = {}
        # APB doesn't split rd/wr — single APBSlave per port.
        self.slave_apb = {}

        # Passive observation buffers for misroute checks.
        # cocotb_bus.monitors.Monitor._recv suppresses _recvQ.append when
        # callbacks are installed. Since the protocol slave BFMs install
        # their auto-response callback, _recvQ never populates and a
        # naive _recvQ check would see "nothing arrived" even when the
        # bridge did route correctly. We install a *second*, passive
        # callback alongside the BFM's response callback that simply
        # appends each observed packet to these per-slave lists.
        self.observed_ar = {i: [] for i in range(4)}
        self.observed_aw = {i: [] for i in range(4)}

        # Master BFMs — separate read and write handles. For wr-only or
        # rd-only masters only one of these gets populated.
        self.master_rd = {}
        self.master_wr = {}
        # APB master (one handle per APB master port).
        self.master_apb = {}

        self._setup_slave_0_periph_slave()
        self._setup_slave_1_ddr0_slave()
        self._setup_slave_2_sram_slave()
        self._setup_slave_3_gpu_mem_slave()
        self._setup_master_0_cpu_master()
        self._setup_master_1_dma0_master()
        self._setup_master_2_dma1_master()
        self._setup_master_3_gpu_master()

    # ----------------------------------------------------------------------
    # Slave seed pattern
    # ----------------------------------------------------------------------

    @staticmethod
    def _seed_value(slave_idx: int, word_offset: int, data_width: int) -> int:
        """Deterministic seed pattern for slave[slave_idx]'s memory.

        Encoding (32-bit case): upper byte = slave_idx+1, lower 24 bits =
        word index. Generalizes to wider data widths by placing the slave
        ID byte in the top byte of the data word (so a hex dump still
        shows the slave ID in the high nibbles).
        """
        id_byte = (slave_idx + 1) & 0xFF
        index_mask = (1 << (data_width - 8)) - 1
        return (id_byte << (data_width - 8)) | (word_offset & index_mask)

    # Cap the per-slave MemoryModel size. The seeded pattern is purely a
    # test fixture — bytes the bridge moves out of memory; the slave's
    # natural addr_range in the TOML can be huge (e.g. 1 GB DDR window)
    # but tests only ever touch a handful of addresses. Eager-filling
    # the full window OOM's the safety monitor (numpy uint8 for data
    # plus two uint32 access-tracking maps = 9 bytes per addressable
    # byte, scaled across multiple multi-hundred-MB slaves).
    #
    # Pre-seed the first SLAVE_MEM_CAP_BYTES of each slave; tests must
    # probe within that window for data verification. Routing-only probes
    # (address_decode beyond page 0) work outside the cap — the framework
    # slave BFMs silently drop OOR writes and fall back to addr-as-data on
    # OOR reads, so the AW/AR routing assertion still fires.
    SLAVE_MEM_CAP_BYTES = 4096

    # Bridge page granularity. The slave-window validator already aligns
    # each base_addr / addr_range to PAGE_SIZE (4 KB), so page-level probes
    # are always safe to construct.
    PAGE_SIZE = 0x1000

    def _build_preset(self, slave_idx: int, addr_range: int, data_width: int) -> bytearray:
        """Build the bytearray preset for a slave's MemoryModel. Caps the
        seeded region at SLAVE_MEM_CAP_BYTES — see the class-level note."""
        bytes_per_word = data_width // 8
        effective = min(addr_range, self.SLAVE_MEM_CAP_BYTES)
        num_words = effective // bytes_per_word
        buf = bytearray(effective)
        for w in range(num_words):
            v = self._seed_value(slave_idx, w, data_width)
            chunk = v.to_bytes(bytes_per_word, 'little')
            buf[w * bytes_per_word:(w + 1) * bytes_per_word] = chunk
        return buf

    def _slave_mem_bytes(self, slave_idx: int) -> int:
        """Return the actual MemoryModel byte capacity for slave_idx
        (= min(addr_range, SLAVE_MEM_CAP_BYTES))."""
        _, _, addr_range, _ = self.slave_info[slave_idx]
        return min(addr_range, self.SLAVE_MEM_CAP_BYTES)

    def slave_probe_pages(self, slave_idx: int, mode: str = 'boundary') -> list:
        """Return absolute page-base addresses to probe within slave_idx's
        window.

        mode='boundary': three pages — first, middle, last of the slave's
            addr_range. For a one-page slave returns [base]; for two pages
            [base, base+PAGE]. This is the default — it exercises low-bit,
            mid-bit, and high-bit address decode without scaling test
            runtime with slave size.

        mode='all': every page in the slave's addr_range. Useful for
            stress / regression on small slaves; large windows (GB-class
            DDR) explode the probe count, so use with care.
        """
        _, base, addr_range, _ = self.slave_info[slave_idx]
        num_pages = max(1, addr_range // self.PAGE_SIZE)
        if mode == 'all':
            return [base + i * self.PAGE_SIZE for i in range(num_pages)]
        # boundary (default)
        if num_pages == 1:
            return [base]
        if num_pages == 2:
            return [base, base + self.PAGE_SIZE]
        mid = (num_pages // 2) * self.PAGE_SIZE
        last = (num_pages - 1) * self.PAGE_SIZE
        return [base, base + mid, base + last]

    def page_probe_offsets(self, slave_idx: int, master_idx: int = 0) -> list:
        """Return three in-page byte offsets [low, mid, high] for probing,
        each aligned to max(master_width, slave_width). Catches address
        decoders that ignore low bits (low probe), mid-bit decoders
        (middle), and decoders that off-by-one at the page boundary
        (high — last aligned word in the page)."""
        master_bytes = self.master_data_width[master_idx] // 8
        slave_bytes = self.slave_info[slave_idx][3] // 8
        align = max(master_bytes, slave_bytes)
        align_mask = ~(align - 1) & 0xFFFFFFFFFFFFFFFF
        low = 0
        mid = (self.PAGE_SIZE // 2) & align_mask
        high = (self.PAGE_SIZE - align) & align_mask
        return [low, mid, high]

    def is_seeded(self, slave_idx: int, addr: int) -> bool:
        """True if `addr` falls inside slave_idx's seeded MemoryModel
        region — i.e. a read at this addr will return the seed pattern
        and a write here is observable via slave_mem_read."""
        _, base, _, _ = self.slave_info[slave_idx]
        offset = addr - base
        return 0 <= offset < self._slave_mem_bytes(slave_idx)

    def expected_pattern(self, slave_idx: int, addr: int) -> int:
        """Return the seeded *master-width* value at the given absolute
        address. Reads `master_data_width_bytes` bytes of memory at
        addr (relative to the slave's base) and interprets little-endian.

        Works for direct paths, width-converted paths, and AXIL-shimmed
        paths uniformly — the bridge moves bytes; we read the same bytes
        back and the master's view is whatever those bytes spell out at
        its data width."""
        # Default to the first master's width — single-master configs
        # this is unambiguous. For multi-master, callers should use
        # slave_mem_read(slave_idx, addr, byte_count=...) explicitly.
        master_width = self.master_data_width.get(0, self.data_width)
        return self.slave_mem_read(slave_idx, addr, byte_count=master_width // 8)

    def slave_mem_read(self, slave_idx: int, addr: int, byte_count: int = None,
                       master_idx: int = 0) -> int:
        """Read `byte_count` bytes from slave[slave_idx]'s memory at
        absolute address `addr` and return as a little-endian int.

        If byte_count is None, derives it from master_idx's data width.
        Defaulting to master 0 covers single-master configs; multi-master
        callers must pass master_idx of the master that wrote (or that
        the master_read will probe), otherwise read-back will include
        stale bytes from the seed pattern beyond what the master touched.
        For APB slaves, reads directly from the APBSlave's internal memory."""
        proto, base, _, slave_dw = self.slave_info[slave_idx]
        if byte_count is None:
            master_width = self.master_data_width.get(master_idx, self.data_width)
            byte_count = master_width // 8
        offset = addr - base
        if proto == 'apb':
            apb = self.slave_apb[slave_idx]
            data_bytes = apb.mem.read(offset, byte_count)
        else:
            mem = self.slave_memory[slave_idx]
            data_bytes = mem.read(offset, byte_count)
        return int.from_bytes(bytes(data_bytes), 'little')

