    def _setup_slave_0_periph_slave(self):
        """Set up protocol BFM and pre-seeded MemoryModel for slave 0: periph_slave (protocol: axi4)"""
        # AXI4 slave — full memory-backed BFM.
        bytes_per_line = 32 // 8
        addr_range = 0x40000000
        # Cap MemoryModel size — see SLAVE_MEM_CAP_BYTES comment.
        mem_bytes = min(addr_range, self.SLAVE_MEM_CAP_BYTES)
        preset = self._build_preset(0, addr_range, 32)
        self.slave_memory[0] = MemoryModel(
            num_lines=mem_bytes // bytes_per_line,
            bytes_per_line=bytes_per_line,
            preset_values=list(preset),
            log=self.log,
        )
        self.slave_rd[0] = AXI4SlaveRead(
            self.dut, self.clock,
            prefix="periph_slave_axi_",
            log=self.log,
            data_width=32,
            addr_width=32,
            id_width=4,
            user_width=1,
            multi_sig=True,
            memory_model=self.slave_memory[0],
            base_addr=0x00000000,
        )
        self.slave_rd[0].ar_channel.add_callback(
            lambda pkt, _i=0: self.observed_ar[_i].append(pkt))
        self.slave_wr[0] = AXI4SlaveWrite(
            self.dut, self.clock,
            prefix="periph_slave_axi_",
            log=self.log,
            data_width=32,
            addr_width=32,
            id_width=4,
            user_width=1,
            multi_sig=True,
            memory_model=self.slave_memory[0],
            base_addr=0x00000000,
        )
        self.slave_wr[0].aw_channel.add_callback(
            lambda pkt, _i=0: self.observed_aw[_i].append(pkt))
